module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [7:0] ext_mul_a = {{4{1'b0}}, mul_a};
    wire [7:0] ext_mul_b = {{4{1'b0}}, mul_b};

    wire [7:0] pp0, pp1, pp2, pp3;
    assign pp0 = (ext_mul_b[0]) ? ext_mul_a : 0;
    assign pp1 = (ext_mul_b[1]) ? ext_mul_a << 1 : 0;
    assign pp2 = (ext_mul_b[2]) ? ext_mul_a << 2 : 0;
    assign pp3 = (ext_mul_b[3]) ? ext_mul_a << 3 : 0;

    reg [7:0] sum_tmp1, sum_tmp2;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            sum_tmp1 <= 0;
            sum_tmp2 <= 0;
        end else begin
            sum_tmp1 <= pp0 + pp1;
            sum_tmp2 <= pp2 + pp3;
        end
    end

    reg [7:0] mul_out_reg;
    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            mul_out_reg <= 0;
        end else begin
            mul_out_reg <= sum_tmp1 + sum_tmp2;
        end
    end

    assign mul_out = mul_out_reg;
endmodule

module verified_multi_pipe#(
	parameter size = 4
)(
	input 						clk 		,   
	input 						rst_n		,
	input	[size-1:0]			mul_a		,
	input	[size-1:0]			mul_b		,

 	output	reg	[size*2-1:0]	mul_out		
);

parameter N = 2 * size;

reg     [N-1:0]     sum_tmp1                ;
reg     [N-1:0]     sum_tmp2                ;
wire    [N-1:0]     mul_a_extend            ;
wire    [N-1:0]     mul_b_extend            ;

wire    [N-1:0]     mul_result[size-1:0]    ;

genvar i;
generate
    for(i = 0; i < size; i = i + 1) begin:add
        assign mul_result[i] = mul_b[i] ? mul_a_extend << i : 'd0;
    end
endgenerate

assign mul_a_extend = {{size{1'b0}}, mul_a};
assign mul_b_extend = {{size{1'b0}}, mul_b};

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum_tmp1 <= 'd0;
        sum_tmp2 <= 'd0;
    end
    else begin
        sum_tmp1 <= mul_result[0] + mul_result[1];
        sum_tmp2 <= mul_result[2] + mul_result[3];
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out <= 'd0;
    end
    else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end

endmodule
